#include <bits/stdc++.h>
using namespace std;
int main()
{
    int n,b,h[20005],s=0,count=0;
    cin>>n>>b;
    for(int i=0;i<=n-1;i++)
    {
        cin>>h[i];
    }
    sort(h,h+n,greater<int>());
    for(int i=0;i<=n-1;i++)
    {
        s+=h[i];
        count++;
        if(s>=b)
        {
            cout<<count;
            return 0;
        }
    }
}
